import{APIResource}from"../../core/resource.js";import{path}from"../../internal/utils/path.js";import{Parts}from"./parts.js";var Uploads=class extends APIResource{constructor(){super(...arguments),this.parts=new Parts(this._client)}create(e,t){return this._client.post(`/uploads`,{body:e,...t,__security:{bearerAuth:!0}})}cancel(e,n){return this._client.post(path`/uploads/${e}/cancel`,{...n,__security:{bearerAuth:!0}})}complete(e,n,r){return this._client.post(path`/uploads/${e}/complete`,{body:n,...r,__security:{bearerAuth:!0}})}};Uploads.Parts=Parts;export{Uploads};